import FormikValidationError from 'components/React/FormikValidationError/FormikValidationError';
import React from 'react';
import { Button } from 'reactstrap';
import { useTranslation } from "react-i18next";
import { testParametersInitialValues, testParametersValidationSchema } from "./schema";


interface Props extends PropsFromRedux {
    editData: any;
    toggle: any;
    setEditData: any;
  }

const Form = (props: Props) => {

    const { t } = useTranslation();

    const [initialData, seetInitialData] = React.useState<typeof testParametersInitialValues>(
        testParametersInitialValues
      );

    React.useEffect(() => {
        if (props.editData) {
          seetInitialData({
            ...props.editData,
            types: PARAMETER_TYPES_OPTIONS.find((item) => item.value === props.editData.types) || null,
          });
        }
      }, [props.editData]);



    return (
        <div>
            <form>
                <div className='row align-items-center'>
                    <div className='col-md-3'>
                        <div className='form-group'>
                            <label htmlFor="" className="mr-1">
                                Parameters Name
                            </label>
                            <input></input>
                        </div>
                    </div>
                    <div className='col-md-3'>
                        <div className='form-group'>
                            <label htmlFor='' className='mr-1'>
                                Unit:
                            </label>
                            <input></input>
                        </div>
                    </div>
                    <div className='col-md-3'>
                        <div className='form-group'>
                            <label htmlFor='' className='mr-1'>
                                NDWQ Standard:
                            </label>
                            <input></input>
                        </div>
                    </div>
                    <div className="col-md-3">
                        <div className="form-group ">
                            <label htmlFor="" className="mr-1">
                                Types
                            </label>

                            <StyledSelect
                                name="types"
                                value={values?.types}
                                options={PARAMETER_TYPES_OPTIONS}
                                onChange={({ name, value }) => {
                                    setFieldValue(name, value);
                                }}
                                onBlur={() => {
                                    setFieldTouched("types", true);
                                }}
                            />
                            <FormikValidationError name="types" errors={errors} touched={touched} />
                        </div>
                    </div>
                    <div className='col-md-12 text-right'>
                        <Button type='submit' className='btn btn-primary' color='primary'
                            style={{
                                padding: "8px 15px",
                                borderRadius: "5px",
                                fontWeight: "bold",
                                letterSpacing: "2px",
                                fontSize: "0.9rem"
                            }}
                        >
                            SAVE
                        </Button>
                    </div>
                </div>
            </form>
        </div>
    )
}

export default Form
